const DATA = [40, 55, 45, 70, 60, 82, 75, 91, 85, 95, 88, 100];
const MONTHS = ["Jan","Feb","Mär","Apr","Mai","Jun","Jul","Aug","Sep","Okt","Nov","Dez"];

export default function ChartLineTrend01() {
  const W = 600;
  const H = 120;
  const max = Math.max(...DATA);
  const pts = DATA.map((v, i) => `${(i / (DATA.length - 1)) * W},${H - (v / max) * H}`).join(" ");
  return (
    <section className="rounded-2xl border border-slate-200 bg-white p-6 dark:border-slate-800 dark:bg-slate-900">
      <div className="flex items-center justify-between">
        <h3 className="text-lg font-semibold text-slate-900 dark:text-white">Jahresverlauf</h3>
        <span className="rounded-full bg-emerald-100 px-2 py-0.5 text-xs font-semibold text-emerald-700">+150% YoY</span>
      </div>
      <div className="mt-4 overflow-hidden">
        <svg viewBox={`0 0 ${W} ${H + 10}`} className="w-full">
          <defs>
            <linearGradient id="lineGrad" x1="0" y1="0" x2="0" y2="1">
              <stop offset="0%" stopColor="#6366F1" stopOpacity="0.4" />
              <stop offset="100%" stopColor="#6366F1" stopOpacity="0" />
            </linearGradient>
          </defs>
          <polygon points={`0,${H} ${pts} ${W},${H}`} fill="url(#lineGrad)" />
          <polyline points={pts} fill="none" stroke="#6366F1" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" />
        </svg>
      </div>
      <div className="mt-2 flex justify-between text-[10px] text-slate-400">
        {MONTHS.map((m) => <span key={m}>{m}</span>)}
      </div>
    </section>
  );
}

import { useEffect, useState } from "react";

const WORDS = ["Wachstum.", "Qualität.", "Vertrauen.", "Ergebnisse."];

export default function HeroTypewriterDark01() {
  const [index, setIndex] = useState(0);
  const [visible, setVisible] = useState(true);

  useEffect(() => {
    const interval = setInterval(() => {
      setVisible(false);
      setTimeout(() => {
        setIndex((i) => (i + 1) % WORDS.length);
        setVisible(true);
      }, 350);
    }, 2500);
    return () => clearInterval(interval);
  }, []);

  return (
    <section className="relative flex min-h-screen items-center justify-center overflow-hidden bg-zinc-950 px-6 text-center">
      <div className="absolute inset-0 bg-[radial-gradient(ellipse_at_center,rgba(161,161,170,0.06),transparent_60%)]" />
      <div className="relative max-w-5xl">
        <p className="mb-6 text-xs font-bold uppercase tracking-[0.4em] text-zinc-500">
          {{projectName}}
        </p>
        <h1 className="text-5xl font-black leading-tight text-white sm:text-6xl lg:text-8xl">
          Wir schaffen <br />
          <span
            className="transition-opacity duration-300 text-transparent bg-clip-text bg-gradient-to-r from-amber-300 to-orange-400"
            style={{ opacity: visible ? 1 : 0 }}
          >
            {WORDS[index]}
          </span>
        </h1>
        <p className="mx-auto mt-8 max-w-xl text-lg text-zinc-400">
          Strategie, Design und Code – vollständig integriert, messbar in Ergebnissen.
        </p>
        <div className="mt-10 flex justify-center gap-4">
          <button className="rounded-full border border-white/20 bg-white/5 px-8 py-3.5 text-sm font-semibold text-white backdrop-blur-sm transition hover:bg-white/10">
